$currentPath=$base!==''&&str_starts_with($requestPath,$base)?substr($requestPath,strlen($base)):$requestPath;
$navCurrent=static function(array $paths)use($currentPath):bool{
  foreach($paths as $path){
    if($currentPath===$path||($path!=='/app'&&str_starts_with($currentPath,$path.'/')))return true;
  }
  return false;
};
